#include <stdio.h>
#include <stdlib.h>

typedef struct Node { long long val; struct Node *next; } Node;

Node* newNode(long long v){ Node* n = (Node*)malloc(sizeof(Node)); n->val=v; n->next=NULL; return n; }

Node* reverseSegment(Node* head, int L, int R){
    Node dummy; dummy.next=head; Node *pre=&dummy;
    for(int i=1;i<L;i++) pre=pre->next;
    Node *start=pre->next;
    for(int i=0;i<R-L;i++){
        Node *tmp=start->next;
        start->next=tmp->next;
        tmp->next=pre->next;
        pre->next=tmp;
    }
    return dummy.next;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,L,R; scanf("%d %d %d",&N,&L,&R);
        Node *head=NULL,*tail=NULL;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld",&x);
            Node* nd=newNode(x);
            if(!head) head=tail=nd; else {tail->next=nd; tail=nd;}
        }
        head=reverseSegment(head,L,R);
        for(Node* cur=head; cur; cur=cur->next){
            printf("%lld",cur->val);
            if(cur->next) printf(" ");
        }
        printf("\n");
        // free list (omitted for brevity)
    }
    return 0;
}

