import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        long val; Node next;
        Node(long v){ val=v; }
    }
    static Node reverseSegment(Node head,int L,int R){
        Node dummy=new Node(0); dummy.next=head;
        Node pre=dummy;
        for(int i=1;i<L;i++) pre=pre.next;
        Node start=pre.next;
        for(int i=0;i<R-L;i++){
            Node tmp=start.next;
            start.next=tmp.next;
            tmp.next=pre.next;
            pre.next=tmp;
        }
        return dummy.next;
    }
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st=new StringTokenizer(br.readLine());
        int T=Integer.parseInt(st.nextToken());
        StringBuilder out=new StringBuilder();
        while(T-- > 0){
            st=new StringTokenizer(br.readLine());
            int N=Integer.parseInt(st.nextToken());
            int L=Integer.parseInt(st.nextToken());
            int R=Integer.parseInt(st.nextToken());
            st=new StringTokenizer(br.readLine());
            Node head=null, tail=null;
            for(int i=0;i<N;i++){
                long x=Long.parseLong(st.nextToken());
                Node nd=new Node(x);
                if(head==null) head=tail=nd; else {tail.next=nd; tail=nd;}
            }
            head=reverseSegment(head,L,R);
            for(Node cur=head; cur!=null; cur=cur.next){
                out.append(cur.val);
                if(cur.next!=null) out.append(' ');
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
}

