const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
function Node(v){ this.val=v; this.next=null; }
function reverseSegment(head, L, R){
    const dummy = new Node(0);
    dummy.next = head;
    let pre = dummy;
    for(let i=1;i<L;i++) pre = pre.next;
    let start = pre.next;
    for(let i=0;i<R-L;i++){
        const tmp = start.next;
        start.next = tmp.next;
        tmp.next = pre.next;
        pre.next = tmp;
    }
    return dummy.next;
}
const T = Number(input[idx++]);
let outputs = [];
for(let t=0;t<T;t++){
    const N = Number(input[idx++]);
    const L = Number(input[idx++]);
    const R = Number(input[idx++]);
    let head=null, tail=null;
    for(let i=0;i<N;i++){
        const nd = new Node(Number(input[idx++]));
        if(!head){head=tail=nd;} else {tail.next=nd; tail=nd;}
    }
    head = reverseSegment(head, L, R);
    const vals = [];
    for(let cur=head; cur; cur=cur.next) vals.push(String(cur.val));
    outputs.push(vals.join(' '));
}
